import React, { useState } from "react";
import "./Internship.css";

export default function Internship() {
  const user = JSON.parse(localStorage.getItem("loggedInUser"));
  const isStudent = user?.role === "Student";

  const [internships, setInternships] = useState([
    {
      title: "Web Developer Intern",
      company: "TechCorp",
      description: "Work on frontend development with React.",
    },
    {
      title: "Data Analyst Intern",
      company: "DataPro",
      description: "Assist with data visualization and reporting.",
    },
  ]);

  const [newInternship, setNewInternship] = useState({
    title: "",
    company: "",
    description: "",
  });

  const [editIndex, setEditIndex] = useState(null);

  const handleChange = (e) => {
    setNewInternship({ ...newInternship, [e.target.name]: e.target.value });
  };

  const handleSubmit = () => {
    if (editIndex !== null) {
      const updated = [...internships];
      updated[editIndex] = newInternship;
      setInternships(updated);
      setEditIndex(null);
    } else {
      setInternships([...internships, newInternship]);
    }
    setNewInternship({ title: "", company: "", description: "" });
  };

  const handleEdit = (index) => {
    setEditIndex(index);
    setNewInternship(internships[index]);
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    setInternships(updated);
  };

  const applyToInternship = (item) => {
    alert(`You applied to ${item.title} at ${item.company}!`);
  };

  return (
    <div className="internship-container">
      <h2>Internships</h2>

      <div className="internship-list">
        {internships.map((item, index) => (
          <div key={index} className="card">
            <h3>{item.title}</h3>
            <p><strong>Company:</strong> {item.company}</p>
            <p>{item.description}</p>

            {isStudent ? (
              <button onClick={() => applyToInternship(item)} className="btn-apply">
                Apply
              </button>
            ) : (
              <div className="admin-actions">
                <button onClick={() => handleEdit(index)}>Edit</button>
                <button onClick={() => handleDelete(index)}>Delete</button>
              </div>
            )}
          </div>
        ))}
      </div>

      {!isStudent && (
        <div className="internship-form">
          <h3>{editIndex !== null ? "Edit" : "Add"} Internship</h3>
          <input
            type="text"
            name="title"
            placeholder="Title"
            value={newInternship.title}
            onChange={handleChange}
          />
          <input
            type="text"
            name="company"
            placeholder="Company"
            value={newInternship.company}
            onChange={handleChange}
          />
          <textarea
            name="description"
            placeholder="Description"
            value={newInternship.description}
            onChange={handleChange}
          ></textarea>
          <button onClick={handleSubmit} className="btn-submit">
            {editIndex !== null ? "Update" : "Add"}
          </button>
        </div>
      )}
    </div>
  );
}
